import { writable, derived } from 'svelte/store';
import { apiClient } from '../utils/api-client';
const initialState = {
    tracks: [],
    scanResult: null,
    isScanning: false,
    isImporting: false,
    scanProgress: 0,
    error: null,
};
export const libraryStore = writable(initialState);
// Derived stores
export const flaggedArtists = derived(libraryStore, ($store) => $store.scanResult?.flagged_artists || []);
export const scanStats = derived(libraryStore, ($store) => $store.scanResult
    ? {
        totalTracks: $store.scanResult.total_tracks,
        totalArtists: $store.scanResult.total_artists,
        flaggedTracks: $store.scanResult.flagged_tracks,
        flaggedArtists: $store.scanResult.flagged_artists.length,
    }
    : null);
